import React, { useMemo } from 'react';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
  Badge,
  Separator
} from "./ui/index.js";
import {
  TrendingDown,
  TrendingUp,
  DollarSign,
  CreditCard,
  Clock,
  BarChart3,
  AlertCircle,
  PieChart,
  BanknoteIcon,
  Wallet,
  ArrowRight,
  ArrowUp,
  ArrowDown,
  Calculator
} from "lucide-react";

/**
 * CostTracker Component
 *
 * Displays AI token usage costs, monthly expenses, and provides budget visualization.
 * Includes savings breakdowns, cost trends, and projected expenses.
 *
 * @typedef {Object} CostData
 * @property {number} [total] - Total cost incurred
 * @property {number} [monthlyCost] - Current month's cost
 * @property {number} [projectedMonthlyCost] - Projected cost for the current month
 * @property {Object} [savings] - Cost savings information
 * @property {number} [savings.total] - Total cost saved
 * @property {number} [savings.caching] - Savings from cache hits
 * @property {number} [savings.optimizations] - Savings from other optimizations
 * @property {Object} [byModel] - Costs broken down by model
 * @property {number} [averageRate] - Average cost per 1K tokens
 *
 * @param {Object} props - Component props
 * @param {CostData} [props.costData={}] - Cost and savings data
 * @param {string} [props.className=''] - Additional CSS class names
 * @param {boolean} [props.darkMode=false] - Whether dark mode is enabled
 *
 * @returns {JSX.Element} Rendered component displaying cost tracking information
 *
 * @example
 * // Basic usage
 * <CostTracker costData={costData} />
 *
 * @example
 * // With dark mode and custom class
 * <CostTracker
 *   costData={costData}
 *   darkMode={true}
 *   className="my-custom-class"
 * />
 */
const CostTracker = ({ costData = {}, className = '', darkMode = false }) => {
  // Format currency with 2 decimal places
  const formatCurrency = (amount) => {
    if (amount === undefined || amount === null) return '—';
    return `$${amount.toFixed(2)}`;
  };

  // Format currency with auto decimal places based on value
  const formatCurrencyAuto = (amount) => {
    if (amount === undefined || amount === null) return '—';

    // For very small values (less than 0.01), show more decimal places
    if (amount < 0.01) {
      return `$${amount.toFixed(5)}`;
    }

    // For small values (less than 1), show 3 decimal places
    if (amount < 1) {
      return `$${amount.toFixed(3)}`;
    }

    // For normal values, show 2 decimal places
    return `$${amount.toFixed(2)}`;
  };

  // Format percentage change with sign
  const formatPercentChange = (value) => {
    if (value === undefined || value === null) return null;
    return {
      value: Math.abs(value).toFixed(1),
      isPositive: value >= 0
    };
  };

  // Helper to get color for cost trends
  const getTrendColorClass = (isPositive) => {
    // For costs, "up" is bad (red), "down" is good (green)
    return isPositive
      ? "bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400"
      : "bg-emerald-100 text-emerald-800 dark:bg-emerald-900/30 dark:text-emerald-400";
  };

  // Handle empty or missing cost data
  if (!costData || Object.keys(costData).length === 0) {
    return (
      <Card className={`${className} shadow-sm hover:shadow-md transition-shadow duration-200`}>
        <CardHeader>
          <CardTitle className="flex items-center">
            <DollarSign className="mr-2 h-5 w-5 text-primary" />
            Cost Tracker
          </CardTitle>
          <CardDescription>
            No cost data available
          </CardDescription>
        </CardHeader>
        <CardContent className="flex flex-col items-center justify-center gap-3 h-48 text-muted-foreground">
          <AlertCircle className="h-10 w-10 text-amber-500 opacity-80" />
          <p className="text-center max-w-[250px]">Cost tracking information will appear here when available</p>
        </CardContent>
      </Card>
    );
  }

  // Extract data with defaults
  const {
    daily = 0,
    monthly = 0,
    dailyChange = 0,
    monthlyChange = 0,
    breakdown = {},
    averageRate = 0
  } = costData;

  // Format changes for display
  const formattedDailyChange = formatPercentChange(dailyChange);
  const formattedMonthlyChange = formatPercentChange(monthlyChange);

  // Calculate total cost for breakdown chart
  const totalCost = Object.values(breakdown).reduce((sum, curr) => sum + curr, 0);

  return (
    <Card className={`${className} shadow-sm hover:shadow-md transition-shadow duration-200`}>
      <CardHeader className="pb-3">
        <CardTitle className="flex items-center">
          <DollarSign className="mr-2 h-5 w-5 text-primary" />
          Cost Tracker
        </CardTitle>
        <CardDescription>
          Track and analyze your AI operation costs
        </CardDescription>
      </CardHeader>

      <CardContent className="space-y-6">
        {/* Main cost metrics with improved layout and responsive design */}
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-6 animate-in fade-in duration-300">
          <div className="space-y-2 p-4 bg-primary/5 dark:bg-primary/10 rounded-lg">
            <div className="flex items-center">
              <Clock className="h-4 w-4 text-muted-foreground mr-2" />
              <div className="text-sm font-medium">Daily Cost</div>
            </div>
            <div className="text-2xl font-bold">{formatCurrency(daily)}</div>

            {formattedDailyChange && (
              <div className="flex items-center gap-2">
                <Badge
                  variant="outline"
                  className={`flex items-center ${getTrendColorClass(formattedDailyChange.isPositive)}`}
                >
                  {formattedDailyChange.isPositive ? (
                    <TrendingUp className="mr-1 h-3 w-3" />
                  ) : (
                    <TrendingDown className="mr-1 h-3 w-3" />
                  )}
                  {formattedDailyChange.value}%
                </Badge>
                <span className="text-xs text-muted-foreground whitespace-nowrap">vs yesterday</span>
              </div>
            )}
          </div>

          <div className="space-y-2 p-4 bg-primary/5 dark:bg-primary/10 rounded-lg">
            <div className="flex items-center">
              <BanknoteIcon className="h-4 w-4 text-muted-foreground mr-2" />
              <div className="text-sm font-medium">Monthly Cost</div>
            </div>
            <div className="text-2xl font-bold">{formatCurrency(monthly)}</div>

            {formattedMonthlyChange && (
              <div className="flex items-center gap-2">
                <Badge
                  variant="outline"
                  className={`flex items-center ${getTrendColorClass(formattedMonthlyChange.isPositive)}`}
                >
                  {formattedMonthlyChange.isPositive ? (
                    <TrendingUp className="mr-1 h-3 w-3" />
                  ) : (
                    <TrendingDown className="mr-1 h-3 w-3" />
                  )}
                  {formattedMonthlyChange.value}%
                </Badge>
                <span className="text-xs text-muted-foreground whitespace-nowrap">vs last month</span>
              </div>
            )}
          </div>
        </div>

        <Separator className="my-1" />

        {/* Cost breakdown by model/category with improved visualization */}
        {breakdown && Object.keys(breakdown).length > 0 && (
          <div className="space-y-4 animate-in fade-in duration-300" style={{ animationDelay: "150ms" }}>
            <div className="flex items-center">
              <PieChart className="mr-2 h-4 w-4 text-primary" />
              <h3 className="text-sm font-medium">Cost Breakdown</h3>
            </div>

            <div className="space-y-3">
              {Object.entries(breakdown).map(([model, cost], index) => {
                // Calculate percentage of total
                const percentage = totalCost > 0 ? (cost / totalCost) * 100 : 0;

                // Generate a color based on the model name (for visual variety)
                const colorVariants = [
                  "primary/70",
                  "blue-500/70",
                  "emerald-500/70",
                  "violet-500/70",
                  "amber-500/70",
                  "pink-500/70"
                ];
                const colorClass = colorVariants[index % colorVariants.length];

                return (
                  <div
                    key={model}
                    className="relative animate-in fade-in slide-in-from-bottom-1 duration-300"
                    style={{ animationDelay: `${index * 50}ms` }}
                  >
                    <div className="flex items-center justify-between mb-1">
                      <div className="flex items-center">
                        <div className={`h-3 w-3 rounded-full bg-${colorClass} mr-2`}></div>
                        <span className="text-sm font-medium">{model}</span>
                      </div>
                      <div className="flex items-center gap-3">
                        <span className="text-sm font-semibold">{formatCurrency(cost)}</span>
                        <Badge variant="outline" className="bg-muted text-muted-foreground text-xs">
                          {percentage.toFixed(1)}%
                        </Badge>
                      </div>
                    </div>
                    <div className="h-2 w-full bg-muted rounded-full overflow-hidden">
                      <div
                        className={`h-full bg-${colorClass} rounded-full transition-all duration-1000 ease-out`}
                        style={{ width: `${percentage}%` }}
                      ></div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        <Separator className="my-1" />

        {/* Rate information with improved visual design */}
        <div className="rounded-lg bg-muted/50 dark:bg-muted/20 p-4 animate-in fade-in duration-300" style={{ animationDelay: "300ms" }}>
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <CreditCard className="h-4 w-4 text-primary" />
              <span className="font-medium text-sm">Average Rate</span>
            </div>
            <TooltipProvider>
              <Tooltip>
                <TooltipTrigger className="font-medium">
                  <Badge variant="outline" className="bg-primary/10 text-primary border-primary/20 dark:bg-primary/20">
                    {formatCurrencyAuto(averageRate)} / 1K tokens
                  </Badge>
                </TooltipTrigger>
                <TooltipContent side="top">
                  <p>Average cost per 1,000 tokens across all models</p>
                </TooltipContent>
              </Tooltip>
            </TooltipProvider>
          </div>

          {costData.projectedMonthlyCost && (
            <div className="mt-4 flex flex-col space-y-2">
              <div className="flex items-center justify-between text-xs">
                <span className="text-muted-foreground flex items-center">
                  <Clock className="mr-1 h-3 w-3" />
                  Projected Monthly Cost:
                </span>
                <span className="font-medium text-sm">
                  {formatCurrency(costData.projectedMonthlyCost)}
                </span>
              </div>

              {/* Add visual representation for projected cost */}
              <div className="h-1.5 w-full bg-muted rounded-full overflow-hidden">
                <div
                  className="h-full bg-primary/60 rounded-full transition-all duration-1000"
                  style={{
                    width: `${Math.min(100, (costData.projectedMonthlyCost / (monthly || 1)) * 100)}%`
                  }}
                ></div>
              </div>

              <div className="flex justify-between text-xs text-muted-foreground pt-1">
                <span>Current: {formatCurrency(monthly)}</span>
                <span>Projected: {formatCurrency(costData.projectedMonthlyCost)}</span>
              </div>
            </div>
          )}
        </div>
      </CardContent>
    </Card>
  );
};

export default CostTracker;

import React from 'react';

/**
 * Enhanced Header component
 * Displays the dashboard title, system health indicator, and view mode controls
 * Implements UI elements for Cline AI dashboard navigation
 * Includes indicator for mock data usage and Magic MCP API status
 */
const EnhancedHeader = ({
  systemHealth = 'optimal',
  activeRequests = 0,
  viewMode = 'overview',
  onViewModeChange,
  onRefresh,
  lastUpdated,
  usingMockData = false,
  className = ''
}) => {
  // Get system health indicator class based on status
  const getHealthClass = () => {
    switch (systemHealth) {
      case 'warning':
        return 'warning';
      case 'critical':
        return 'critical';
      case 'optimal':
      default:
        return 'optimal';
    }
  };

  // Format last updated timestamp
  const getLastUpdatedText = () => {
    if (!lastUpdated) return 'Never updated';

    try {
      const timeString = lastUpdated.toLocaleTimeString([], {
        hour: '2-digit',
        minute: '2-digit'
      });
      return `Updated at ${timeString}`;
    } catch (e) {
      return 'Unknown update time';
    }
  };

  return (
    <header className={`header ${className}`}>
      <div className="header-title-area">
        <h1 className="header-title">Cline AI Dashboard</h1>
        <div className="header-subtitle">
          Token Optimization Monitor
          {usingMockData && <span className="mock-data-indicator"> (Mock Data)</span>}
        </div>
      </div>

      <div className="header-actions">
        <div className="system-status">
          <div className={`status-indicator ${getHealthClass()}`}></div>
          <div className="status-text">
            System: {systemHealth} {activeRequests > 0 && `(${activeRequests} active)`}
          </div>
          <div className="last-updated-text">{getLastUpdatedText()}</div>
        </div>

        <div className="view-selector">
          <div
            className={`view-option ${viewMode === 'overview' ? 'active' : ''}`}
            onClick={() => onViewModeChange && onViewModeChange('overview')}
            data-testid="overview-view-option"
          >
            Overview
          </div>
          <div
            className={`view-option ${viewMode === 'detailed' ? 'active' : ''}`}
            onClick={() => onViewModeChange && onViewModeChange('detailed')}
            data-testid="detailed-view-option"
          >
            Detailed
          </div>
          <div
            className={`view-option ${viewMode === 'settings' ? 'active' : ''}`}
            onClick={() => onViewModeChange && onViewModeChange('settings')}
            data-testid="settings-view-option"
          >
            Settings
          </div>
        </div>

        <div className="action-buttons">
          <button
            className="refresh-button"
            onClick={onRefresh}
            title="Refresh dashboard data"
            data-testid="refresh-button"
          >
            🔄
          </button>

          {usingMockData && (
            <button
              className="magic-mcp-button"
              onClick={onRefresh}
              title="Using mock data - click to retry connecting to MCP server"
              data-testid="magic-mcp-button"
            >
              ✨
            </button>
          )}
        </div>
      </div>
    </header>
  );
};

export default EnhancedHeader;

import React, { useState } from 'react';

/**
 * Header component
 * Displays the dashboard title, system health indicator, and view mode controls
 * Implements UI elements for Cline AI dashboard navigation
 */
export const Header = ({
  systemHealth = 'optimal',
  activeRequests = 0,
  viewMode = 'overview',
  onViewModeChange,
  onRefresh,
  lastUpdated,
  className = ''
}) => {
  const [isDarkTheme, setIsDarkTheme] = useState(false);

  // Function to toggle theme
  const toggleTheme = () => {
    setIsDarkTheme(!isDarkTheme);
    document.body.classList.toggle('dark-theme');

    // For test compatibility
    if (typeof window !== 'undefined') {
      window.__TEST_ONLY_toggleTheme && window.__TEST_ONLY_toggleTheme();
    }
  };

  // Get system health indicator class based on status
  const getHealthClass = () => {
    switch (systemHealth) {
      case 'warning':
        return 'bg-warning';
      case 'critical':
        return 'bg-error';
      case 'optimal':
      default:
        return 'bg-success';
    }
  };

  // Format last updated timestamp
  const getLastUpdatedText = () => {
    if (!lastUpdated) return 'Never updated';

    try {
      const timeString = lastUpdated.toLocaleTimeString([], {
        hour: '2-digit',
        minute: '2-digit'
      });
      return `Updated at ${timeString}`;
    } catch (e) {
      return 'Unknown update time';
    }
  };

  return (
    <header className={`flex justify-between items-center mb-4 pb-3 border-b border-border ${className}`}>
      <div className="flex flex-col">
        <h1 className="text-2xl font-semibold m-0">
          Cline AI Dashboard
        </h1>
        <div className="text-sm text-muted-foreground">
          Token Usage Statistics & Performance Metrics
        </div>
      </div>

      <div className="flex items-center gap-4">
        <div className="flex items-center gap-2">
          <div className={`w-2.5 h-2.5 rounded-full ${getHealthClass()}`}></div>
          <span className="text-sm font-medium">{systemHealth}</span>
          {activeRequests > 0 && (
            <span className="text-sm text-muted-foreground ml-2">
              ({activeRequests} active {activeRequests === 1 ? 'request' : 'requests'})
            </span>
          )}
          <span className="text-sm text-muted-foreground ml-3">
            {getLastUpdatedText()}
          </span>
        </div>

        <div className="flex bg-card border border-border rounded-md overflow-hidden">
          <button
            className={`px-3 py-1 cursor-pointer text-sm font-medium transition-colors ${
              viewMode === 'overview'
                ? 'bg-primary text-primary-foreground'
                : 'hover:bg-background'
            }`}
            onClick={() => onViewModeChange('overview')}
            data-testid="overview-tab"
          >
            Overview
          </button>
          <button
            className={`px-3 py-1 cursor-pointer text-sm font-medium transition-colors ${
              viewMode === 'detailed'
                ? 'bg-primary text-primary-foreground'
                : 'hover:bg-background'
            }`}
            onClick={() => onViewModeChange('detailed')}
            data-testid="detailed-tab"
          >
            Detailed
          </button>
          <button
            className={`px-3 py-1 cursor-pointer text-sm font-medium transition-colors ${
              viewMode === 'settings'
                ? 'bg-primary text-primary-foreground'
                : 'hover:bg-background'
            }`}
            onClick={() => onViewModeChange('settings')}
            data-testid="settings-tab"
          >
            Settings
          </button>
        </div>

        <div className="flex gap-2">
          <button
            className="bg-card border border-border rounded-md px-3 py-1 cursor-pointer transition-all hover:bg-background hover:shadow-sm"
            onClick={onRefresh}
            data-testid="refresh-button"
          >
            Refresh
          </button>
          <button
            className="bg-primary-foreground border border-border rounded-md px-3 py-1 cursor-pointer transition-all hover:bg-primary hover:text-primary-foreground"
            onClick={toggleTheme}
            data-testid="theme-toggle"
          >
            {isDarkTheme ? 'Light Mode' : 'Dark Mode'}
          </button>
        </div>
      </div>
    </header>
  );
};

export default Header;

import React, { useMemo } from 'react';
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
  Badge,
  Separator
} from "./ui/index.js";
import {
  TrendingUp,
  TrendingDown,
  Zap,
  Database,
  Clock,
  Users,
  Server,
  Activity,
  BarChart4
} from "lucide-react";

/**
 * MetricsPanel Component
 *
 * Displays key system metrics in a clean, modern card layout with animated data visualization
 *
 * @param {Object} props Component props
 * @param {Object} props.metrics System metrics data
 * @param {String} props.className Additional CSS classes
 * @param {Boolean} props.darkMode Whether dark mode is enabled
 */
function MetricsPanel({ metrics = {}, className = '', darkMode = false }) {
  // Helper to format percentage changes
  const formatChange = (value) => {
    if (value === undefined || value === null) return null;

    const formatted = Math.abs(value).toFixed(1);
    const direction = value >= 0 ? 'up' : 'down';
    return { value: formatted, direction };
  };

  // Use sensible defaults for missing metrics
  const defaultMetrics = {
    avgResponseTime: 0.8,
    cacheHitRate: 0.0,
    dailyActiveUsers: 0,
    completionRate: 0.0,
    reliability: 99.5,
  };

  // Map API metrics to component metrics with fallbacks
  const mappedMetrics = useMemo(() => ({
    responseTime: metrics?.avgResponseTime ?? defaultMetrics.avgResponseTime,
    responseTimeChange: metrics?.responseTimeChange ?? 0,
    cacheHitRate: metrics?.cacheHitRate ?? defaultMetrics.cacheHitRate,
    cacheHitRateChange: metrics?.cacheHitRateChange ?? 0,
    activeSessions: metrics?.dailyActiveUsers ?? defaultMetrics.dailyActiveUsers,
    activeSessionsChange: metrics?.activeSessionsChange ?? 0,
    systemLoad: metrics?.completionRate ?? defaultMetrics.completionRate,
    systemLoadChange: metrics?.systemLoadChange ?? 0,
    reliability: metrics?.reliability ?? defaultMetrics.reliability,
    reliabilityChange: metrics?.reliabilityChange ?? 0,
  }), [metrics]);

  // Define metrics cards with icons, formatters, and visualization settings
  const metricCards = useMemo(() => [
    {
      id: 'responseTime',
      title: 'Response Time',
      value: `${mappedMetrics.responseTime.toFixed(1)}ms`,
      change: formatChange(mappedMetrics.responseTimeChange),
      icon: <Clock className="h-4 w-4" />,
      description: 'Average AI response time',
      // For response time, down is good (faster)
      changeIsBetter: (direction) => direction === 'down',
      color: 'blue',
      progressValue: Math.min(mappedMetrics.responseTime / 10, 1) * 100, // Scale for visualization
      ariaLabel: `Response time is ${mappedMetrics.responseTime.toFixed(1)} milliseconds`
    },
    {
      id: 'cacheHitRate',
      title: 'Cache Hit Rate',
      value: `${(mappedMetrics.cacheHitRate * 100).toFixed(1)}%`,
      change: formatChange(mappedMetrics.cacheHitRateChange),
      icon: <Database className="h-4 w-4" />,
      description: 'Percentage of requests served from cache',
      // For cache hit rate, up is good
      changeIsBetter: (direction) => direction === 'up',
      color: 'emerald',
      progressValue: mappedMetrics.cacheHitRate * 100,
      ariaLabel: `Cache hit rate is ${(mappedMetrics.cacheHitRate * 100).toFixed(1)} percent`
    },
    {
      id: 'reliability',
      title: 'Reliability',
      value: `${mappedMetrics.reliability.toFixed(1)}%`,
      change: formatChange(mappedMetrics.reliabilityChange),
      icon: <Zap className="h-4 w-4" />,
      description: 'System reliability and uptime percentage',
      // For reliability, up is good
      changeIsBetter: (direction) => direction === 'up',
      color: 'indigo',
      progressValue: mappedMetrics.reliability,
      ariaLabel: `System reliability is ${mappedMetrics.reliability.toFixed(1)} percent`
    },
    {
      id: 'systemLoad',
      title: 'System Load',
      value: `${(mappedMetrics.systemLoad * 100).toFixed(1)}%`,
      change: formatChange(mappedMetrics.systemLoadChange),
      icon: <Server className="h-4 w-4" />,
      description: 'Current system resource utilization',
      // For system load, down is good (less load)
      changeIsBetter: (direction) => direction === 'down',
      color: 'amber',
      progressValue: mappedMetrics.systemLoad * 100,
      ariaLabel: `System load is ${(mappedMetrics.systemLoad * 100).toFixed(1)} percent`
    }
  ], [mappedMetrics]);

  // Get CSS classes for specific color themes
  const getColorClasses = (color, type) => {
    const colorMap = {
      blue: {
        bg: darkMode ? 'bg-blue-900/20' : 'bg-blue-100',
        bgFill: darkMode ? 'bg-blue-600/70' : 'bg-blue-500/70',
        text: darkMode ? 'text-blue-400' : 'text-blue-600',
      },
      emerald: {
        bg: darkMode ? 'bg-emerald-900/20' : 'bg-emerald-100',
        bgFill: darkMode ? 'bg-emerald-600/70' : 'bg-emerald-500/70',
        text: darkMode ? 'text-emerald-400' : 'text-emerald-600',
      },
      indigo: {
        bg: darkMode ? 'bg-indigo-900/20' : 'bg-indigo-100',
        bgFill: darkMode ? 'bg-indigo-600/70' : 'bg-indigo-500/70',
        text: darkMode ? 'text-indigo-400' : 'text-indigo-600',
      },
      amber: {
        bg: darkMode ? 'bg-amber-900/20' : 'bg-amber-100',
        bgFill: darkMode ? 'bg-amber-600/70' : 'bg-amber-500/70',
        text: darkMode ? 'text-amber-400' : 'text-amber-600',
      },
      violet: {
        bg: darkMode ? 'bg-violet-900/20' : 'bg-violet-100',
        bgFill: darkMode ? 'bg-violet-600/70' : 'bg-violet-500/70',
        text: darkMode ? 'text-violet-400' : 'text-violet-600',
      }
    };

    return colorMap[color]?.[type] || '';
  };

  // If no metrics data, show placeholder with improved loading state
  if (!metrics || Object.keys(metrics).length === 0) {
    return (
      <div
        className={`grid gap-4 ${className} grid-cols-1 sm:grid-cols-2 lg:grid-cols-4`}
        aria-label="Loading metrics dashboard"
      >
        {metricCards.map((metric) => (
          <Card
            key={metric.id}
            className="hover:shadow-md transition-all duration-200 overflow-hidden border border-border/50"
            aria-busy="true"
          >
            <CardHeader className="flex flex-row items-center justify-between pb-2">
              <CardTitle className="text-sm font-medium">
                {metric.title}
              </CardTitle>
              <TooltipProvider>
                <Tooltip delayDuration={300}>
                  <TooltipTrigger asChild>
                    <div className={`rounded-full ${getColorClasses(metric.color, 'bg')} p-1.5 ${getColorClasses(metric.color, 'text')} opacity-80`}>
                      {metric.icon}
                    </div>
                  </TooltipTrigger>
                  <TooltipContent side="top">
                    <p>{metric.description}</p>
                  </TooltipContent>
                </Tooltip>
              </TooltipProvider>
            </CardHeader>
            <CardContent>
              <div className="text-2xl font-bold text-muted-foreground animate-pulse">
                {metric.value} <span className="text-xs font-normal">(Default)</span>
              </div>
              <div className="mt-2 flex items-center gap-1">
                <span className="text-xs text-muted-foreground">Awaiting data...</span>
              </div>

              {/* Loading state for the bar */}
              <div className="mt-3 pt-3 border-t border-border">
                <div className="h-1.5 w-full bg-muted rounded-full overflow-hidden">
                  <div className="h-full rounded-full bg-muted-foreground/30 animate-pulse" style={{ width: '50%' }}></div>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>
    );
  }

  return (
    <div
      className={`grid gap-4 ${className} grid-cols-1 sm:grid-cols-2 lg:grid-cols-4`}
      aria-label="Performance metrics dashboard"
    >
      {metricCards.map((metric, index) => (
        <Card
          key={metric.id}
          className={`hover:shadow-md transition-all duration-300 overflow-hidden border border-border/60
                      animate-in fade-in slide-in-from-bottom-3
                     ${darkMode ? 'bg-card/95' : 'bg-card'}`}
          style={{ animationDelay: `${index * 75}ms` }}
          aria-labelledby={`metric-title-${metric.id}`}
        >
          <CardHeader className="flex flex-row items-center justify-between pb-2">
            <CardTitle className="text-sm font-medium" id={`metric-title-${metric.id}`}>
              {metric.title}
            </CardTitle>
            <TooltipProvider>
              <Tooltip delayDuration={300}>
                <TooltipTrigger asChild>
                  <div
                    className={`rounded-full ${getColorClasses(metric.color, 'bg')} p-1.5 ${getColorClasses(metric.color, 'text')}`}
                    aria-hidden="true"
                  >
                    {metric.icon}
                  </div>
                </TooltipTrigger>
                <TooltipContent side="top">
                  <p>{metric.description}</p>
                </TooltipContent>
              </Tooltip>
            </TooltipProvider>
          </CardHeader>
          <CardContent className="pt-2">
            <div className="text-2xl font-bold" aria-label={metric.ariaLabel}>
              {metric.value}
            </div>

            {metric.change && (
              <div className="mt-2 flex items-center gap-1">
                <Badge
                  variant="outline"
                  className={
                    metric.changeIsBetter(metric.change.direction)
                      ? "bg-emerald-100 text-emerald-800 dark:bg-emerald-900/30 dark:text-emerald-400"
                      : "bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400"
                  }
                  aria-label={`${metric.change.direction === 'up' ? 'Increased' : 'Decreased'} by ${metric.change.value} percent`}
                >
                  {metric.change.direction === 'up' ? (
                    <TrendingUp className="mr-1 h-3 w-3" aria-hidden="true" />
                  ) : (
                    <TrendingDown className="mr-1 h-3 w-3" aria-hidden="true" />
                  )}
                  {metric.change.value}%
                </Badge>
                <span className="text-xs text-muted-foreground">vs last period</span>
              </div>
            )}

            {/* Visual representation of the metric with animated progress */}
            <div className="mt-3 pt-3 border-t border-border">
              <div
                className="h-2 w-full bg-muted rounded-full overflow-hidden"
                role="progressbar"
                aria-valuenow={metric.progressValue}
                aria-valuemin="0"
                aria-valuemax="100"
              >
                <div
                  className={`h-full rounded-full transition-all duration-1000 ease-in-out ${getColorClasses(metric.color, 'bgFill')}`}
                  style={{ width: `${metric.progressValue}%` }}
                ></div>
              </div>
            </div>
          </CardContent>
        </Card>
      ))}
    </div>
  );
}

export default MetricsPanel;

import React, { useState, useEffect, useMemo } from 'react';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Badge,
  Button,
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
  Separator
} from './ui/index.js';
import {
  Code2,
  BrainCircuit,
  TextIcon,
  Eye,
  Calculator,
  CheckCircle,
  CheckCircle2,
  Sparkles,
  ChevronsUpDown
} from 'lucide-react';

/**
 * ModelSelector Component
 *
 * Displays available AI models with their capabilities and specifications
 * Allows users to select which model to use
 * Shows recommendations for different task types
 *
 * @param {Object} props Component props
 * @param {Array|Object} props.models Available models
 * @param {String} props.selectedModel Currently selected model ID
 * @param {Function} props.onModelChange Callback for model selection
 * @param {Function} props.onModelSelect Legacy callback for model selection
 * @param {Object} props.modelData Structured model data
 * @param {Boolean} props.darkMode Whether dark mode is enabled
 */
const ModelSelector = ({
  models,
  selectedModel,
  onModelChange,
  onModelSelect,
  modelData,
  className = '',
  darkMode = false
}) => {
  // Allow both ways of passing props for backward compatibility with tests
  // Add compatibility with both onModelChange and onModelSelect prop names
  const handleModelChange = onModelChange || onModelSelect;

  const modelInfo = modelData || {
    selected: selectedModel,
    available: models && Object.entries(models).map(([id, details]) => ({
      id,
      ...details
    })),
    recommendedFor: {}
  };

  if (!modelInfo && !models) {
    return null;
  }

  const { selected, available, recommendedFor } = modelInfo;

  // Format token count with K suffix
  const formatTokenCount = (count) => {
    if (count === undefined || count === null) {
      return '0K';
    }
    return `${(count / 1000).toFixed(0)}K`;
  };

  // Format cost per token
  const formatCostPerToken = (cost) => {
    if (cost === undefined || cost === null) {
      return '$0.00000/token';
    }
    if (cost < 0.0001) {
      return `$${(cost * 1000000).toFixed(2)}/1M tokens`;
    }
    return `$${cost.toFixed(5)}/token`;
  };

  // Helper to determine if a model is recommended for a specific task
  const isRecommendedFor = (modelId, task) => {
    return recommendedFor && recommendedFor[task] === modelId;
  };

  // Helper to get color variants for each capability
  const getCapabilityColorClass = (capability) => {
    const classes = {
      code: 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300',
      reasoning: 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-300',
      text: 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-300',
      vision: 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-300',
      math: 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-300'
    };

    return classes[capability] || 'bg-gray-100 text-gray-700 dark:bg-gray-800 dark:text-gray-300';
  };

  return (
    <Card className={`${className} shadow-sm h-full`}>
      <CardHeader className="pb-3">
        <div className="flex justify-between items-center">
          <CardTitle className="text-xl">
            <div className="flex items-center">
              <Sparkles className="mr-2 h-5 w-5 text-primary" />
              Model Selection
            </div>
          </CardTitle>
          <Badge variant="outline" className="bg-muted/50 text-muted-foreground">
            {(available && available.length) || 0} available
          </Badge>
        </div>
        <CardDescription>
          Choose the best AI model for your needs
        </CardDescription>
      </CardHeader>

      <CardContent className="space-y-6">
        <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-3">
          {available && (Array.isArray(available) ? available : Object.values(available)).map((model, index) => {
            const isSelected = model.id === selected;

            // For test compatibility
            const modelId = model.id;

            // Calculate tasks this model is recommended for
            const recommendedTasks = recommendedFor ? Object.entries(recommendedFor)
              .filter(([_, recModelId]) => recModelId === model.id)
              .map(([task]) => task) : [];

            return (
              <div
                key={model.id || `model-${index}`}
                data-testid={`model-card-${model.id}`}
                className={`relative rounded-lg border overflow-hidden transition-all duration-200 hover:shadow-md ${
                  isSelected
                    ? 'border-primary bg-primary/5 dark:bg-primary/10'
                    : 'border-border hover:border-primary/60'
                }`}
                onClick={() => handleModelChange(model.id)}
              >
                <div className="p-4 space-y-4 cursor-pointer">
                  <div className="flex justify-between items-center">
                    <div
                      className="font-medium text-base"
                      data-testid={`model-name-${model.id}`}
                    >
                      {model.name}
                    </div>

                    {isSelected && (
                      <Badge className="bg-primary hover:bg-primary text-primary-foreground py-1">
                        Current
                      </Badge>
                    )}
                  </div>

                  <div className="flex flex-wrap gap-2">
                    {model.capabilities && model.capabilities.map((capability, capIndex) => (
                      <TooltipProvider key={`${model.id}-${capability}-${capIndex}`}>
                        <Tooltip>
                          <TooltipTrigger asChild>
                            <div className={`flex items-center justify-center w-8 h-8 rounded-full ${getCapabilityColorClass(capability)}`}>
                              {getCapabilityIcon(capability)}
                            </div>
                          </TooltipTrigger>
                          <TooltipContent side="top">
                            <p>{capability.charAt(0).toUpperCase() + capability.slice(1)} capability</p>
                          </TooltipContent>
                        </Tooltip>
                      </TooltipProvider>
                    ))}
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <div className="text-xs text-muted-foreground">Context</div>
                      <div className="font-medium">{formatTokenCount(model.contextWindow)}</div>
                    </div>
                    <div>
                      <div className="text-xs text-muted-foreground">Cost</div>
                      <div className="font-medium">{formatCostPerToken(model.costPerToken)}</div>
                    </div>
                  </div>

                  {recommendedTasks.length > 0 && (
                    <div>
                      <div className="text-xs text-muted-foreground mb-1.5">Recommended for:</div>
                      <div className="flex flex-wrap gap-1.5">
                        {recommendedTasks.map((task, taskIndex) => (
                          <Badge
                            key={`${model.id}-${task}-${taskIndex}`}
                            variant="outline"
                            className="bg-primary/10 text-primary border-primary/20 dark:bg-primary/20 text-xs font-normal"
                          >
                            {formatTaskName(task)}
                          </Badge>
                        ))}
                      </div>
                    </div>
                  )}

                  <Button
                    variant={isSelected ? "secondary" : "default"}
                    size="sm"
                    className={`w-full mt-2 ${isSelected ? 'bg-primary/20 hover:bg-primary/20 text-primary dark:bg-primary/30' : ''}`}
                    disabled={isSelected}
                    onClick={(e) => {
                      e.stopPropagation();
                      if (!isSelected) {
                        handleModelChange(model.id);
                      }
                    }}
                  >
                    {isSelected ? (
                      <div className="flex items-center">
                        <CheckCircle2 className="mr-1 h-4 w-4" />
                        Selected
                      </div>
                    ) : 'Select'}
                  </Button>
                </div>
              </div>
            );
          })}
        </div>

        {/* Model Recommendations */}
        {recommendedFor && Object.keys(recommendedFor).length > 0 && (
          <div className="mt-auto pt-4">
            <Separator className="mb-4" />

            <div className="space-y-3">
              <h3 className="text-sm font-medium">Recommended Models by Task</h3>

              <div className="grid gap-2 sm:grid-cols-2">
                {Object.entries(recommendedFor).map(([task, modelId]) => {
                  const modelArray = Array.isArray(available) ? available : Object.values(available);
                  const recommendedModel = available && modelArray.find(model => model.id === modelId);
                  if (!recommendedModel) return null;

                  return (
                    <div key={task} className="flex items-center justify-between p-2 rounded-md border border-border">
                      <div className="text-sm">{formatTaskName(task)}</div>
                      <div className="flex items-center gap-1.5">
                        <div
                          className="w-2.5 h-2.5 rounded-full"
                          style={{ backgroundColor: getModelColor(modelId) }}
                        ></div>
                        <div className="text-sm font-medium">{recommendedModel.name.split(' ').pop()}</div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
};

// Helper functions for icons and formatting
const getCapabilityIcon = (capability) => {
  switch (capability) {
    case 'code':
      return <Code2 className="h-4 w-4" />;
    case 'reasoning':
      return <BrainCircuit className="h-4 w-4" />;
    case 'text':
      return <TextIcon className="h-4 w-4" />;
    case 'vision':
      return <Eye className="h-4 w-4" />;
    case 'math':
      return <Calculator className="h-4 w-4" />;
    default:
      return <CheckCircle className="h-4 w-4" />;
  }
};

const formatTaskName = (task) => {
  const formattedNames = {
    codeCompletion: 'Code Completion',
    errorResolution: 'Error Resolution',
    architecture: 'Architecture',
    thinking: 'Thinking',
    basicTasks: 'Basic Tasks'
  };

  return formattedNames[task] || task.charAt(0).toUpperCase() + task.slice(1);
};

const getModelColor = (modelId) => {
  const colors = {
    'claude-3.7-sonnet': '#7b68ee',
    'gemini-2.5-flash': '#4285f4',
    'claude-3.7-haiku': '#9575cd'
  };

  return colors[modelId] || '#999';
};

export { ModelSelector };
export default ModelSelector;

