                    ) : (
                      <>
                        <TrendingDown className="h-3 w-3 mr-1" />
                        {comparisonData.percentageChange.averageDailyUsage.toFixed(1)}%
                      </>
                    )}
                    <span className="text-muted-foreground ml-1">vs previous</span>
                  </div>
